// Generated by flappy-bird/tools/generate_skin_rom.py.
// Sprite display size is 21x21. Source frames may be 1..8 frames per skin.
module skin_info(
    input  wire [2:0] skin_id,
    output reg  [3:0] frame_count
);
    always @(*) begin
        case (skin_id)
            3'd0: frame_count = 4'd6; // original
            3'd1: frame_count = 4'd6; // dyb
            3'd2: frame_count = 4'd6; // qiu_shi_ying
            3'd3: frame_count = 4'd6; // space
            default: frame_count = 4'd0;
        endcase
    end
endmodule

